// === Каталог продуктов «Делай Дело» ===
// ВАЖНО: цены ДОЛЖНЫ совпадать со значениями `price` в src/content/products/*.md
// и Pro‑тарифами на сайте калькулятора. Если меняешь цену — синхронно обнови оба места.
const CATALOG = {
  // Маркетплейсы
  'unit-economy-excel':      { title: 'Юнит‑экономика SKU для WB и Ozon — калькулятор',           price: 690 },
  'wbozon-zero-to-100k':     { title: 'Core‑гайд: WB и Ozon с нуля до первой 100 000 ₽ оборота',  price: 1490 },
  'wb-ozon-card-seo':        { title: 'SEO карточек WB и Ozon: ключи, заголовки, описания',       price: 990 },
  'wb-ozon-reviews':         { title: 'Управление отзывами WB и Ozon: шаблоны и сценарии',        price: 690 },
  'wb-card-prompts':         { title: 'Промпт‑пак: AI‑описания карточек WB и Ozon',               price: 590 },
  'china-suppliers':         { title: 'Поставщики из Китая для WB и Ozon',                        price: 990 },
  'wb-internal-ads':         { title: 'Внутренняя реклама WB: настройка и оптимизация',           price: 990 },
  'ozon-after-wb':           { title: 'Выход на Ozon после WB: что делать иначе',                 price: 690 },
  'yandex-market-launch':    { title: 'Запуск на Яндекс.Маркете: пошаговый гайд',                 price: 690 },
  // Самозанятые / ИП
  'self-employed-coreguide': { title: 'Core‑гайд самозанятого: запуск и первые 10 клиентов',      price: 1290 },
  'self-employed-finance':   { title: 'Финансовый учёт самозанятого',                             price: 690 },
  'services-marketplaces':   { title: 'Маркетплейсы услуг: Avito, Profi.ru, YouDo, Я.Услуги',     price: 590 },
  'raise-price-scripts':     { title: 'Скрипты переписки: как поднять цену услуги',               price: 590 },
  'services-time-planning':  { title: 'Планирование времени и защита от выгорания для мастера',   price: 590 },
  'services-targeted-ads':   { title: 'Таргет VK Ads и Яндекс.Директ для услуг',                  price: 990 },
  'services-word-of-mouth':  { title: 'Сарафанное радио и система отзывов для самозанятого',      price: 490 },
  // Pro‑тарифы калькулятора
  'calc-pro-year':           { title: 'Калькулятор юнит‑экономики Pro — доступ на год',           price: 2990 },
  'calc-pro-lifetime':       { title: 'Калькулятор юнит‑экономики Pro — пожизненный доступ',      price: 9900 }
};

// Куда возвращать после оплаты. Поменяй на боевой домен при переезде с GitHub Pages.
const RETURN_URL = 'https://delo-delai.ru/thanks/';
const PROJECT_ID = 'delaydelo';

// === Валидация входа: жёсткие whitelist-проверки ===
const body = (items[0].json && items[0].json.body) || items[0].json || {};
const project = (body.project || '').toString();
const slug = (body.guide_slug || '').toString();
const email = (body.email || '').toString().trim();
const idempotenceKey = (body.idempotence_key || '').toString().trim();
const sourceUrl = (body.source_url || '').toString().trim();
const priceCheck = Number(body.price_kopeks_check || 0);

// 0) Этот воркфлоу обслуживает ТОЛЬКО проект delaydelo.
if (project !== PROJECT_ID) {
  throw new Error('Project mismatch: expected ' + PROJECT_ID + ', got ' + project);
}

// 1) slug — только из каталога
if (!slug || !Object.prototype.hasOwnProperty.call(CATALOG, slug)) {
  throw new Error('Unknown guide_slug: ' + slug);
}

// 2) email — узкий безопасный набор символов
const EMAIL_RE = /^[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}$/;
if (!email || email.length > 254 || !EMAIL_RE.test(email)) {
  throw new Error('Invalid email');
}

// 3) idempotence_key — UUID-подобная строка
const IDEMP_RE = /^[A-Za-z0-9._\-]{8,128}$/;
if (!IDEMP_RE.test(idempotenceKey)) {
  throw new Error('Invalid idempotence_key');
}

// 4) source_url — http(s), без кавычек/обратных слэшей
let safeSourceUrl = '';
if (sourceUrl) {
  if (sourceUrl.length > 2048 || /["\\]/.test(sourceUrl) || !/^https?:\/\//.test(sourceUrl)) {
    throw new Error('Invalid source_url');
  }
  safeSourceUrl = sourceUrl;
}

const product = CATALOG[slug];
const priceValue = product.price.toFixed(2); // 'NNNN.00'

// 5) Защита от подмены цены клиентом — если фронт прислал price_kopeks_check, он должен сходиться.
// Несовпадение НЕ блокирует платёж (вдруг мы изменили цену в каталоге между сборкой и кликом),
// но логируется в metadata, чтобы потом разобраться.
let priceMismatch = '';
if (priceCheck && Math.abs(priceCheck - product.price * 100) > 0) {
  priceMismatch = String(priceCheck);
}

const paymentBody = {
  amount: { value: priceValue, currency: 'RUB' },
  capture: true,
  confirmation: {
    type: 'redirect',
    return_url: RETURN_URL + slug + '/'
  },
  description: product.title,
  metadata: {
    project: PROJECT_ID,
    guide_slug: slug,
    email,
    source_url: safeSourceUrl,
    price_mismatch: priceMismatch
  },
  receipt: {
    customer: { email },
    items: [
      {
        description: product.title,
        quantity: '1.00',
        amount: { value: priceValue, currency: 'RUB' },
        vat_code: 1,
        payment_subject: 'service',
        payment_mode: 'full_prepayment'
      }
    ]
  }
};

return [{
  json: {
    idempotence_key: idempotenceKey,
    payment_body: paymentBody
  }
}];
